previewCss:
.darma-loader-darma-custom-634 {color: var(--loader-color, #0ea5e9);
  --loader-secondary-color: var(--loader-secondary-color, #67e8f9);
  --loader-bg: var(--loader-bg, #ffffff);
   width: 90px;
   height: 14px;
   box-shadow: 0 3px 0 currentColor;
   background: repeating-linear-gradient(90deg,currentColor 0 14px,#0000 0 100%) 0 0/calc(100%/4) 100%;
   animation: darma-loader-darma-custom-634-l1 1s infinite linear;
}
@keyframes darma-loader-darma-custom-634-l1  {
  100% {background-position:calc(100%/3) 0}
}

